3	import {SETTINGS_QUERY_ENGINE} from "../../../config";
4	import usePrestoSearchState from "../SearchState/Presto";
5	import {PRESTO_SQL_INTERFACE} from "../SearchState/Presto/typings";
6	import NativeControls from "./Native/NativeControls";
7	import FreeformControls from "./Presto/Freeform/FreeformControls";
8	import GuidedControls from "./Presto/Guided/GuidedControls";
9	
10	
11	/**
12	 * Prevents the default behavior to avoid page reload when submitting query.
13	 *
14	 * @param ev
15	 */
16	const handleSubmit = (ev: React.FormEvent<HTMLFormElement>) => {
17	    ev.preventDefault();
18	};
19	
20	/**
21	 * Renders controls for submitting queries and the query status.
22	 *
23	 * @return
24	 */
25	const SearchControls = () => {
26	    const sqlInterface = usePrestoSearchState((state) => state.sqlInterface);
27	    const isPrestoGuided = sqlInterface === PRESTO_SQL_INTERFACE.GUIDED;
28	
29	    let controls;
30	    if (SETTINGS_QUERY_ENGINE !== CLP_QUERY_ENGINES.PRESTO) {
31	        controls = <NativeControls/>;
32	    } else if (isPrestoGuided) {
33	        controls = <GuidedControls/>;
34	    } else {
35	        controls = <FreeformControls/>;
36	    }
37	
38	    return (
39	        <form onSubmit={handleSubmit}>
40	            {controls}
41	        </form>
42	    );
43	};
