1	import {message} from "antd";
2	import {Dayjs} from "dayjs";
3	import {create} from "zustand";
4	
5	import {TimelineConfig} from "../../../components/ResultsTimeline/typings";
6	import {downloadTextFile} from "../../../utils/download";
7	import {
8	    DEFAULT_TIME_RANGE,
9	    DEFAULT_TIME_RANGE_OPTION,
10	    TIME_RANGE_OPTION,
11	} from "../SearchControls/TimeRangeInput/utils";
12	import {
13	    formatResultAsJsonl,
14	    SearchResult,
15	} from "../SearchResults/SearchResultsTable/Native/SearchResultsVirtualTable/typings";
16	import {formatExportFilenameTimestamp} from "../SearchResults/SearchResultsTable/Native/utils";
17	import {computeTimelineConfig} from "../SearchResults/SearchResultsTimeline/utils";
18	import {SEARCH_UI_STATE} from "./typings";
19	
20	
21	/**
22	 * Default values of the search state.
23	 */
24	const SEARCH_STATE_DEFAULT = Object.freeze({
25	    aggregationJobId: null,
26	    numSearchResultsMetadata: 0,
27	    numSearchResultsTable: 0,
28	    numSearchResultsTimeline: 0,
29	    queriedDatasets: [],
30	    queryIsCaseSensitive: false,
31	    queryString: "",
32	    searchJobId: null,
33	    searchResults: null as SearchResult[] | null,
34	    searchUiState: SEARCH_UI_STATE.DEFAULT,
35	    selectedDatasets: [],
36	    timeRange: DEFAULT_TIME_RANGE,
37	    timeRangeOption: DEFAULT_TIME_RANGE_OPTION,
38	    timelineConfig: computeTimelineConfig(DEFAULT_TIME_RANGE),
39	});
40	
41	interface SearchState {
42	    /**
43	     * Unique ID from the database for the aggregation job.
44	     */
45	    aggregationJobId: string | null;
46	
47	    /**
48	     * The number of search results from server metadata.
49	     */
50	    numSearchResultsMetadata: number;
51	
52	    /**
53	     * The number of search table results.
54	     */
55	    numSearchResultsTable: number;
56	
57	    /**
58	     * The number of timeline results.
59	     */
60	    numSearchResultsTimeline: number;
61	
62	    /**
63	     * Datasets that were included in the most recently submitted query. Separate from
64	     * `selectedDatasets` so that post-submission UI changes don't affect in-flight query state.
65	     */
66	    queriedDatasets: string[];
67	
68	    /**
69	     * Whether the query is case sensitive.
70	     */
71	    queryIsCaseSensitive: boolean;
72	
73	    /**
74	     * The search query string.
75	     */
76	    queryString: string;
77	
78	    /**
79	     * Unique ID from the database for the search job.
80	     */
81	    searchJobId: string | null;
82	
83	    /**
84	     * Current search results from the cursor subscription.
85	     */
86	    searchResults: SearchResult[] | null;
87	
88	    /**
89	     * UI state of search page.
90	     */
91	    searchUiState: SEARCH_UI_STATE;
92	
93	    /**
94	     * Datasets currently selected in the UI dropdown.
95	     */
96	    selectedDatasets: string[];
97	
98	    /**
99	     * Time range for search query.
100	     */
101	    timeRange: [Dayjs, Dayjs];
102	
103	    /**
104	     * Time range preset.
105	     */
106	    timeRangeOption: TIME_RANGE_OPTION;
107	
108	    /**
109	     * Time range and bucket duration for the timeline. The timeline config should
110	     * only be updated when queries are submitted and not when the range picker
111	     * selection is changed.
112	     */
113	    timelineConfig: TimelineConfig;
114	
115	    /**
116	     * Exports all search results as a JSONL file download.
117	     *
118	     * NOTE: Results are exported in the original cursor order (i.e., timestamp descending),
119	     * which may differ from the user's current table sort.
120	     */
121	    handleSearchResultsExport: () => void;
122	
123	    updateAggregationJobId: (id: string | null) => void;
124	    updateNumSearchResultsMetadata: (num: number) => void;
125	    updateNumSearchResultsTable: (num: number) => void;
126	    updateNumSearchResultsTimeline: (num: number) => void;
127	    updateQueriedDatasets: (datasets: string[]) => void;
128	    updateQueryIsCaseSensitive: (newValue: boolean) => void;
129	    updateQueryString: (query: string) => void;
130	    updateSearchJobId: (id: string | null) => void;
131	    updateSearchResults: (results: SearchResult[] | null) => void;
132	    updateSearchUiState: (state: SEARCH_UI_STATE) => void;
133	    updateSelectedDatasets: (datasets: string[]) => void;
134	    updateTimeRange: (range: [Dayjs, Dayjs]) => void;
135	    updateTimeRangeOption: (option: TIME_RANGE_OPTION) => void;
136	    updateTimelineConfig: (config: TimelineConfig) => void;
137	}
138	
139	const useSearchStore = create<SearchState>((set, get) => ({
140	    ...SEARCH_STATE_DEFAULT,
141	
142	    handleSearchResultsExport: () => {
143	        const {searchResults} = get();
144	        if (null === searchResults || 0 === searchResults.length) {
145	            return;
146	        }
147	
148	        try {
149	            downloadTextFile(
150	                searchResults.map((r) => `${formatResultAsJsonl(r)}\n`),
151	                `clp-search-results-${formatExportFilenameTimestamp()}.jsonl`
152	            );
153	            message.success(`Exported ${searchResults.length} results`);
154	        } catch (e) {
155	            message.error("Failed to export results");
156	            console.error(e);
157	        }
158	    },
159	    updateAggregationJobId: (id) => {
160	        set({aggregationJobId: id});
161	    },
162	    updateNumSearchResultsMetadata: (num) => {
163	        set({numSearchResultsMetadata: num});
164	    },
165	    updateNumSearchResultsTable: (num) => {
166	        set({numSearchResultsTable: num});
167	    },
168	    updateNumSearchResultsTimeline: (num) => {
169	        set({numSearchResultsTimeline: num});
170	    },
171	    updateQueriedDatasets: (datasets) => {
172	        set({queriedDatasets: datasets});
173	    },
174	    updateQueryIsCaseSensitive: (newValue) => {
175	        set({queryIsCaseSensitive: newValue});
176	    },
177	    updateQueryString: (query) => {
178	        set({queryString: query});
179	    },
180	    updateSearchJobId: (id) => {
181	        set({searchJobId: id});
182	    },
183	    updateSearchResults: (results) => {
184	        set({searchResults: results});
185	    },
186	    updateSearchUiState: (state) => {
187	        set({searchUiState: state});
188	    },
189	    updateSelectedDatasets: (datasets) => {
190	        set({selectedDatasets: datasets});
191	    },
192	    updateTimeRange: (range) => {
193	        set({timeRange: range});
194	    },
195	    updateTimeRangeOption: (option) => {
196	        set({timeRangeOption: option});
197	    },
198	    updateTimelineConfig: (config) => {
199	        set({timelineConfig: config});
200	    },
201	}));
202	
203	
204	export {SEARCH_STATE_DEFAULT};
205	export default useSearchStore;
