1	import {
2	    useMutation,
3	    useQueryClient,
4	} from "@tanstack/react-query";
5	import {
6	    CLP_STORAGE_ENGINES,
7	    STORAGE_TYPE,
8	} from "@webui/common/config";
9	import {
10	    CompressionJobInputType,
11	    FsCompressionJobCreation,
12	} from "@webui/common/schemas/compression";
13	import {
14	    Col,
15	    Form,
16	    Input,
17	    Radio,
18	    Row,
19	    Typography,
20	} from "antd";
21	
22	import {
23	    submitCompressionJob,
24	    submitScannerJob,
25	} from "../../../api/compress";
26	import {DashboardCard} from "../../../components/DashboardCard";
27	import {
28	    SETTINGS_LOGS_INPUT_TYPE,
29	    SETTINGS_STORAGE_ENGINE,
30	} from "../../../config";
31	import ClpSFormItems from "./ClpSFormItems";
32	import {
33	    LOGS_TYPE_HELPER_TEXT,
34	    TIMESTAMP_KEY_HELPER_TEXT,
35	} from "./formConstants";
36	import {
37	    applyClpSFields,
38	    buildS3Payload,
39	    filterValidS3Paths,
40	    getSuccessMessage,
41	    type SubmitResult,
42	} from "./jobHelpers";
43	import PathsSelectFormItem from "./PathsSelectFormItem";
44	import S3InputFormItems from "./S3InputFormItems";
45	import ScannerAdvancedFormItems from "./ScannerAdvancedFormItems";
46	import SubmitFormItem from "./SubmitFormItem";
47	
48	
49	type FormValues = {
50	    bucket?: string;
51	    bufferChannelCapacity?: number;
52	    bufferFlushThresholdBytes?: number;
53	    bufferTimeoutSec?: number;
54	    dataset?: string;
55	    ingestMode?: string;
56	    paths?: string[];
57	    regionCode?: string;
58	    s3Paths?: string[];
59	    scanningIntervalSec?: number;
60	    timestampKey?: string;
61	    unstructured?: boolean;
62	};
63	
64	const isS3Input = STORAGE_TYPE.S3 === SETTINGS_LOGS_INPUT_TYPE;
65	const INGEST_MODE_ONE_TIME = "one-time";
66	const INGEST_MODE_SCANNER = "scanner";
67	const showClpSFields = CLP_STORAGE_ENGINES.CLP_S === SETTINGS_STORAGE_ENGINE;
68	const TIMESTAMP_KEY_PLACEHOLDER =
69	    "The path (e.g. x.y) for the field containing the log event's timestamp";
70	const RADIO_BUTTON_STYLE = {width: "50%", textAlign: "center" as const};
71	
72	/**
73	 * Builds and submits the appropriate job based on form values.
74	 *
75	 * @param values
76	 * @return
77	 */
78	const submitJob = async (values: FormValues): Promise<SubmitResult> => {
79	    const isScanner = isS3Input && INGEST_MODE_SCANNER === values.ingestMode;
80	
81	    if (isS3Input) {
82	        const payload = buildS3Payload({
83	            bucket: values.bucket as string,
84	            regionCode: values.regionCode as string,
85	            s3Paths: filterValidS3Paths(values.s3Paths),
86	            scanner: isScanner,
87	            values: values,
88	        });
89	
90	        if (isScanner) {
91	            const result = await submitScannerJob(payload);
92	
93	            return {jobIds: result.jobIds, type: "scanner"};
94	        }
95	
96	        const result = await submitCompressionJob(payload);
97	
98	        return {jobId: result.jobId, type: "compression"};
99	    }
100	
101	    const fsPayload: FsCompressionJobCreation = {
102	        inputType: CompressionJobInputType.FS,
103	        paths: values.paths as string[],
104	    };
105	
106	    if (showClpSFields) {
107	        applyClpSFields(fsPayload, values);
108	    }
109	
110	    const result = await submitCompressionJob(fsPayload);
111	
112	    return {jobId: result.jobId, type: "compression"};
113	};
114	
115	/**
116	 * Renders submit result feedback.
117	 *
118	 * @param isSuccess
119	 * @param isError
120	 * @param data
121	 * @param error
122	 * @return
123	 */
124	const renderFeedback = (
125	    isSuccess: boolean,
126	    isError: boolean,
127	    data: SubmitResult | undefined,
128	    error: Error | null,
129	) => {
130	    if (isSuccess) {
131	        return (
132	            <Typography.Text type={"success"}>
133	                {getSuccessMessage(data as SubmitResult)}
134	            </Typography.Text>
135	        );
136	    }
137	    if (isError) {
138	        return (
139	            <Typography.Text type={"danger"}>
140	                {"Failed to submit job: "}
141	                {error instanceof Error ?
142	                    error.message :
143	                    "Unknown error"}
144	            </Typography.Text>
145	        );
146	    }
147	
148	    return null;
149	};
150	
151	/**
152	 * Renders a compression job submission form.
153	 *
154	 * @return
155	 */
156	const Compress = () => {
157	    const [form] = Form.useForm<FormValues>();
158	    const ingestMode = Form.useWatch("ingestMode", form);
159	    const unstructured = Form.useWatch<boolean>("unstructured", form);
160	    const isScanner = isS3Input && INGEST_MODE_SCANNER === ingestMode;
161	    const queryClient = useQueryClient();
162	    const {
163	        mutate,
164	        isPending: isSubmitting,
165	        isSuccess,
166	        isError,
167	        data,
168	        error,
169	    } = useMutation({
170	        mutationFn: submitJob,
171	        onSettled: async () => {
172	            await queryClient.invalidateQueries({queryKey: ["jobs"]});
173	        },
174	        onSuccess: () => {
175	            form.resetFields();
176	        },
177	    });
178	
179	    return (
180	        <DashboardCard title={"Submit Compression Job"}>
181	            <Form
182	                form={form}
183	                layout={"vertical"}
184	                requiredMark={"optional"}
185	                onFinish={mutate}
186	            >
187	                {isS3Input && (
188	                    <Row gutter={8}>
189	                        <Col span={5}>
190	                            <Form.Item
191	                                initialValue={INGEST_MODE_ONE_TIME}
192	                                label={"Job Type"}
193	                                name={"ingestMode"}
194	                                required={true}
195	                                tooltip={
196	                                    "Scanner: continuously polls S3 for new objects and" +
197	                                    " compresses them automatically."
198	                                }
199	                            >
200	                                <Radio.Group style={{width: "100%"}}>
201	                                    <Radio.Button
202	                                        style={RADIO_BUTTON_STYLE}
203	                                        value={INGEST_MODE_ONE_TIME}
204	                                    >
