62	                },
63	                tags: ["Search"],
64	            },
65	        },
66	        // eslint-disable-next-line max-lines-per-function
67	        async (request, reply) => {
68	            const {
69	                datasets,
70	                timestampBegin,
71	                timestampEnd,
72	                ignoreCase,
73	                timeRangeBucketSizeMillis,
74	                queryString,
75	            } = request.body as QueryJobCreation;
