161	                    [constants.HTTP_STATUS_INTERNAL_SERVER_ERROR]: ErrorSchema,
162	                },
163	                tags: ["Search"],
164	            },
165	        },
166	        async (request, reply) => {
167	            const {searchJobId, aggregationJobId} = request.body as QueryJob;
168	
169	            request.log.info({
170	                searchJobId,
171	                aggregationJobId,
172	            }, "api/search/results args");
173	
174	            await mongoDb.collection(searchJobId.toString()).drop();
175	            await mongoDb.collection(aggregationJobId.toString()).drop();
176	
177	            reply.code(constants.HTTP_STATUS_NO_CONTENT);
178	
179	            return null;
180	        }
181	    );
182	
183	
184	    fastify.post(
185	        "/cancel",
186	        {
187	            schema: {
188	                body: QueryJobSchema as never,
189	                response: {
190	                    [constants.HTTP_STATUS_NO_CONTENT]: Type.Null(),
191	                    [constants.HTTP_STATUS_INTERNAL_SERVER_ERROR]: ErrorSchema,
192	                },
193	                tags: ["Search"],
194	            },
195	        },
196	        async (request, reply) => {
197	            const {searchJobId, aggregationJobId} = request.body as QueryJob;
198	
199	            request.log.info({
200	                searchJobId,
201	                aggregationJobId,
202	            }, "api/search/cancel args");
203	
204	            try {
205	                await QueryJobDbManager.cancelJob(searchJobId);
206	                await QueryJobDbManager.cancelJob(aggregationJobId);
207	
208	                await searchResultsMetadataCollection.updateOne(
209	                    {
