64	class RateLimiter {
65	    private hits = new Map<string, {count: number; resetAt: number}>();
66	
67	    private maxHits: number;
68	
69	    private windowMs: number;
70	
71	    constructor (maxHits: number, windowMs: number) {
72	        this.maxHits = maxHits;
73	        this.windowMs = windowMs;
74	    }
75	
76	    check (ip: string): {allowed: boolean; remaining: number; resetAt: number} {
77	        const now = Date.now();
78	        let entry = this.hits.get(ip);
79	        if (!entry || now >= entry.resetAt) {
80	            entry = {count: 0, resetAt: now + this.windowMs};
81	            this.hits.set(ip, entry);
82	        }
83	        entry.count++;
84	        const allowed = entry.count <= this.maxHits;
85	        return {allowed: allowed, remaining: Math.max(0, this.maxHits - entry.count), resetAt: entry.resetAt};
86	    }
87	}
