152	        const {allowed, remaining, resetAt} = dashboardLimiter.check(ip);
153	        c.header("X-RateLimit-Remaining", String(remaining));
154	        c.header("X-RateLimit-Reset", String(Math.ceil(resetAt / MS_PER_SECOND)));
155	        if (!allowed) {
156	            c.status(HTTP_RATE_LIMITED);
157	
158	            return c.json({error: "Rate limit exceeded. Try again later."});
159	        }
160	
161	        return next();
162	    })
163	    .use("/api/dashboards/*", async (c, next) => {
164	        const contentLength = c.req.raw.headers.get("content-length");
165	        if (contentLength && parseInt(contentLength, 10) > MAX_BODY_SIZE) {
