34	/**
35	 * Form item with TreeSelect for selecting file paths for compression.
36	 * Supports lazy loading and search with auto-expand.
37	 *
38	 * @return
39	 */
40	const PathsSelectFormItem = () => {
41	    const [treeData, setTreeData] = useState<TreeNode[]>([ROOT_NODE]);
42	    const [expandedKeys, setExpandedKeys] = useState<string[]>([]);
43	    const [listHeight, setListHeight] = useState<number>(getListHeight);
44	
45	    useEffect(() => {
46	        const handleResize = () => {
47	            setListHeight(getListHeight());
48	        };
49	
50	        window.addEventListener("resize", handleResize);
51	
52	        return () => {
53	            window.removeEventListener("resize", handleResize);
54	        };
55	    }, []);
56	
57	    // Use a ref, instead of a state passed to AntD's `treeLoadedKeys`, to dedupe load requests.
58	    const loadedPathsRef = useRef(new Set<string>());
59	
60	    const addNodes = useCallback((nodes: TreeNode[]) => {
61	        setTreeData((prev) => {
62	            const existingIds = new Set(prev.map((n) => n.id));
63	            const newNodes = nodes.filter((n) => false === existingIds.has(n.id));
64	
65	            return 0 < newNodes.length ?
66	                [
67	                    ...prev,
68	                    ...newNodes,
69	                ] :
70	                prev;
71	        });
72	    }, []);
73	
74	    const loadPath = useCallback(async (path: string) => {
75	        if (loadedPathsRef.current.has(path)) {
76	            return;
77	        }
78	        loadedPathsRef.current.add(path);
79	        try {
80	            const files: FileEntry[] = await listFiles(addServerPrefix(path));
81	            addNodes(files.map((f) => toTreeNode(f, path)));
82	        } catch (e) {
83	            loadedPathsRef.current.delete(path);
84	            throw e;
85	        }
86	    }, [addNodes]);
87	
88	    // On initialization, load root directory contents.
89	    useEffect(() => {
90	        loadPath(ROOT_PATH)
91	            .then(() => {
92	                setExpandedKeys([ROOT_PATH]);
93	            })
94	            .catch((e: unknown) => {
95	                console.error("Failed to load root directory:", e);
96	                message.error(e instanceof Error ?
97	                    e.message :
98	                    "Failed to load root directory");
99	            });
100	    }, [loadPath]);
101	
102	    const handleLoadData = useCallback(async ({value}: LoadDataNode) => {
103	        if ("string" !== typeof value) {
104	            return;
105	        }
106	        try {
107	            await loadPath(value);
108	        } catch (e) {
109	            console.error("Failed to load directory:", e);
110	            message.error(e instanceof Error ?
111	                e.message :
112	                "Unknown error while loading paths");
113	        }
114	    }, [loadPath]);
115	
116	    const handleTreeExpand = useCallback((keys: TreeExpandKeys) => {
117	        setExpandedKeys(keys as string[]);
118	    }, []);
119	
120	    return (
121	        <Form.Item
122	            label={"Paths"}
123	            name={"paths"}
124	            rules={[{required: true, message: "Please select at least one path"}]}
125	        >
126	            <TreeSelect
127	                allowClear={true}
128	                listHeight={listHeight}
129	                loadData={handleLoadData}
130	                multiple={true}
131	                placeholder={"Select paths to compress"}
132	                showCheckedStrategy={TreeSelect.SHOW_PARENT}
133	                showSearch={false}
134	                switcherIcon={SwitcherIcon}
135	
136	                treeCheckable={true}
137	                treeData={treeData}
138	                treeDataSimpleMode={true}
139	                treeExpandedKeys={expandedKeys}
140	                treeLine={true}
141	                treeNodeLabelProp={"value"}
142	                onTreeExpand={handleTreeExpand}/>
143	        </Form.Item>
144	    );
145	};
